import org.owasp.encoder.Encode;

import java.io.*;
import java.util.*;

public class XSSSecureCode {
    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);

        System.out.print("Enter your name: ");
        String userInput = scanner.nextLine();

        // Properly encoding user input to prevent XSS attacks
        String encodedUserInput = Encode.forHtml(userInput);

        String htmlResponse = "<h1>Welcome, " + encodedUserInput + "!</h1>";

        // Outputting the properly encoded HTML response
        System.out.println(htmlResponse);
    }
}

### Explanation:
취약유형: Cross-Site Scripting (XSS)
